// modules/Problems/services/ProblemsService.js

const { Pool } = require('pg');
const pool = new Pool();

async function solve({ difficulty, limit, tags, tagsArray }) {
  // Normalize and combine tags filter from comma-separated string or array
  let filterTags = [];
  if (tags) {
    filterTags = tags.split(',').map(t => t.trim().toLowerCase()).filter(t => t.length > 0);
  }
  if (Array.isArray(tagsArray)) {
    filterTags = filterTags.concat(tagsArray.map(t => String(t).trim().toLowerCase()).filter(t => t.length > 0));
  }
  // Deduplicate tags
  filterTags = [...new Set(filterTags)];

  // Build SQL query parts
  const params = [];
  let whereClauses = [];
  if (difficulty) {
    params.push(difficulty);
    whereClauses.push(`difficulty = $${params.length}`);
  }

  if (filterTags.length > 0) {
    // Use EXISTS with unnest to check if problem tags overlap with filterTags
    params.push(filterTags);
    whereClauses.push(`EXISTS (
      SELECT 1 FROM unnest(tags) tag WHERE lower(tag) = ANY($${params.length})
    )`);
  }

  const whereSQL = whereClauses.length > 0 ? `WHERE ${whereClauses.join(' AND ')}` : '';

  // Stable sort by problem id ascending
  const sql = `
    SELECT id, name, difficulty, tags
    FROM problems
    ${whereSQL}
    ORDER BY id ASC
    LIMIT ${limit ? parseInt(limit, 10) : 100}
  `;

  const { rows } = await pool.query(sql, params);

  // Compose metadata with appliedTags normalized
  const metadata = {
    appliedTags: filterTags,
  };

  return { problems: rows, metadata };
}

module.exports = { solve };
